#include <bits/stdc++.h>
using namespace std;
int n,m,sum;
map<string,int> id;
string name[2500006];
vector<int> b[2500006];
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        int l;
        string s;
        scanf("%d",&l);
        while(l--){
            cin>>s;
            if(!id[s])
                id[s]=++sum,name[sum]=s;
            if(!b[id[s]].size() || b[id[s]][b[id[s]].size()-1]!=i)
                b[id[s]].push_back(i);
        }
    }
    scanf("%d",&m);
    while(m--){
        string s;
        cin>>s;
        int len=b[id[s]].size();
        for(int i=0;i<len;i++)
            printf("%d ",b[id[s]][i]);
        printf("\n");
    }
    return 0;
}
